#include <bits/stdc++.h>
using namespace std;

const int N=5310,M=5e5+10,INF=1e8;

int n,cnt,deg[N];
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int S,T,f[N],dis[N],pre[N],ans,q[N];
bool inq[N];

void add(int x,int y,int a,int b){
    ver[++tot]=y,edge[tot]=a,val[tot]=b,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,val[tot]=-b,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(dis,0x3f,sizeof(dis));
    memset(inq,0,sizeof(inq));
    int hh=1,tt=0;
    dis[S]=0,f[S]=INF;
    q[++tt]=S,inq[S]=1;
    while(hh<=tt){
        int x=q[hh++];
        inq[x]=0;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && dis[y=ver[i]]>dis[x]+val[i]){
                dis[y]=dis[x]+val[i];
                f[y]=min(f[x],edge[i]);
                pre[y]=i;
                if(!inq[y]) q[++tt]=y,inq[y]=1;
            }
    }
    return dis[T]<INF;
}

void Update(){
    int p=T,flow=f[T];
    ans+=f[T]*dis[T];
    while(p!=S){
        int i=pre[p];
        edge[i]-=flow,edge[i^1]+=flow;
        p=ver[i^1];
    }
}

int main(){
    scanf("%d",&n);
    S=1,T=n+1;
    cnt=n+1;
    for(int i=1;i<=n;i++){
        int k,b,t;
        scanf("%d",&k);
        while(k--){
            scanf("%d%d",&b,&t);
            cnt++;
            add(i,cnt,INF,t);
            add(cnt,b,INF,0);
            add(cnt,T,1,0);
            deg[b]++;
        }
    }
    for(int i=1;i<=n;i++)
        if(deg[i])
            add(S,i,deg[i],0);
    while(bfs())
        Update();
    printf("%d",ans);
    return 0;
}
